    pub fn range(&self) -> (f64, f64) {
        match self {
            DiscriminationBand::Poor => (-1.0, 0.1),
            DiscriminationBand::Acceptable => (0.1, 0.3),
            DiscriminationBand::Good => (0.3, 0.5),
            DiscriminationBand::Excellent => (0.5, 1.0001),
        }
    }
}
