{"file_path": "/home/abdelah/Documents/eaglepoint/TASK-32-W2/repo/style/main.scss", "content": "/* ScholarVault — Golden-Gradient Premium SaaS Theme
 * CSS variables drive every component color so the theme can be tuned in one place.
 */

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --bg-primary:   #0A0A0F;
  --bg-secondary: #12121A;
  --bg-card:      #1A1A28;
  --bg-hover:     #1F1F32;
  --gold-400:     #F5C518;
  --gold-500:     #E8A900;
  --gold-600:     #CC8800;
  --gradient-gold: linear-gradient(135deg, #F5C518 0%, #E8A900 50%, #CC8800 100%);
  --shadow-gold:  0 0 20px rgba(245, 197, 24, 0.15);
  --shadow-gold-strong: 0 0 30px rgba(245, 197, 24, 0.30);
  --text-primary:   #F0F0F5;
  --text-secondary: #A0A0B0;
  --text-gold:      #F5C518;
  --border-subtle:  rgba(245, 197, 24, 0.15);
  --border-strong:  rgba(245, 197, 24, 0.40);
  --danger:  #EF4444;
  --success: #10B981;
  --warning: #F59E0B;
}

html, body {
  margin: 0;
  padding: 0;
  background: var(--bg-primary);
  color: var(--text-primary);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
  font-size: 14px;
  line-height: 1.5;
  -webkit-font-smoothing: antialiased;
  min-height: 100vh;
}

* { box-sizing: border-box; }

a { color: var(--gold-400); text-decoration: none; }
a:hover { color: var(--gold-500); }

/* ----- Reusable component classes ----- */

.sv-card {
  background: var(--bg-card);
  border: 1px solid var(--border-subtle);
  border-left: 3px solid var(--gold-500);
  border-radius: 10px;
  padding: 20px;
  box-shadow: var(--shadow-gold);
}

.sv-card:hover { box-shadow: var(--shadow-gold-strong); }

.sv-btn-primary {
  background: var(--gradient-gold);
  color: #0A0A0F;
  font-weight: 600;
  padding: 10px 20px;
  border-radius: 8px;
  border: none;
  cursor: pointer;
  transition: transform 0.1s, box-shadow 0.2s;
}
.sv-btn-primary:hover { box-shadow: var(--shadow-gold-strong); transform: translateY(-1px); }
.sv-btn-primary:disabled { opacity: 0.55; cursor: not-allowed; transform: none; }

.sv-btn-secondary {
  background: transparent;
  color: var(--gold-400);
  border: 1px solid var(--gold-500);
  padding: 10px 20px;
  border-radius: 8px;
  font-weight: 600;
  cursor: pointer;
}
.sv-btn-secondary:hover { background: rgba(245,197,24,0.08); }

.sv-btn-danger {
  background: var(--danger);
  color: #fff;
  border: none;
  padding: 10px 20px;
  border-radius: 8px;
  font-weight: 600;
  cursor: pointer;
}

.sv-btn-ghost {
  background: transparent;
  color: var(--text-secondary);
  border: 1px solid transparent;
  padding: 8px 14px;
  border-radius: 6px;
  cursor: pointer;
}
.sv-btn-ghost:hover { background: var(--bg-hover); color: var(--text-primary); }

.sv-input {
  background: var(--bg-secondary);
  border: 1px solid var(--border-subtle);
  color: var(--text-primary);
  padding: 10px 14px;
  border-radius: 8px;
  width: 100%;
  font-size: 14px;
  outline: none;
  transition: border-color 0.15s, box-shadow 0.15s;
}
.sv-input:focus {
  border-color: var(--gold-400);
  box-shadow: 0 0 0 3px rgba(245,197,24,0.20);
}

.sv-label {
  display: block;
  font-size: 12px;
  color: var(--text-secondary);
  margin-bottom: 6px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.sv-badge {
  display: inline-block;
  padding: 3px 10px;
  border-radius: 999px;
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.03em;
  text-transform: uppercase;
}
.sv-badge-gold { background: var(--gradient-gold); color: #0A0A0F; }
.sv-badge-success { background: rgba(16,185,129,0.15); color: var(--success); border: 1px solid rgba(16,185,129,0.40); }
.sv-badge-danger  { background: rgba(239,68,68,0.15); color: var(--danger); border: 1px solid rgba(239,68,68,0.40); }
.sv-badge-warning { background: rgba(245,158,11,0.15); color: var(--warning); border: 1px solid rgba(245,158,11,0.40); }
.sv-badge-info    { background: rgba(96,165,250,0.15); color: #60a5fa; border: 1px solid rgba(96,165,250,0.40); }

.sv-table {
  width: 100%;
  border-collapse: collapse;
  background: var(--bg-card);
  border-radius: 10px;
  overflow: hidden;
}
.sv-table th {
  text-align: left;
  padding: 12px 16px;
  font-size: 11px;
  color: var(--text-gold);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 1px solid var(--border-subtle);
  background: var(--bg-secondary);
}
.sv-table td {
  padding: 12px 16px;
  font-size: 13px;
  border-bottom: 1px solid rgba(255,255,255,0.04);
}
.sv-table tr:hover td { background: var(--bg-hover); }

.sv-skeleton {
  background: linear-gradient(90deg, #1A1A28 0%, #2A2A38 50%, #1A1A28 100%);
  background-size: 1000px 100%;
  animation: shimmer 2s infinite linear;
  border-radius: 6px;
}

@keyframes shimmer {
  0% { background-position: -1000px 0; }
  100% { background-position: 1000px 0; }
}

.sv-text-gradient {
  background: var(--gradient-gold);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.sv-sidebar {
  width: 240px;
  background: var(--bg-secondary);
  border-right: 1px solid var(--border-subtle);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.sv-sidebar-item {
  display: flex;
  align-items: center;
  padding: 10px 18px;
  color: var(--text-secondary);
  border-left: 3px solid transparent;
  cursor: pointer;
  transition: all 0.15s;
}
.sv-sidebar-item:hover { background: var(--bg-hover); color: var(--text-primary); }
.sv-sidebar-item.active {
  background: var(--bg-hover);
  color: var(--gold-400);
  border-left-color: var(--gold-400);
}

.sv-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.75);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
}

.sv-modal {
  background: var(--bg-card);
  border: 1px solid var(--border-strong);
  border-radius: 12px;
  padding: 28px;
  min-width: 480px;
  max-width: 90vw;
  max-height: 90vh;
  overflow-y: auto;
  box-shadow: var(--shadow-gold-strong);
}

.sv-error {
  color: var(--danger);
  font-size: 12px;
  margin-top: 4px;
}
"}

