        .unwrap_or_else(|_| "scholarvault-aes256-key-32bytes!!".to_string());
    let signing_key = std::env::var("SIGNING_KEY")
        .unwrap_or_else(|_| "scholarvault-jwt-signing-key-secret!".to_string());
