async fn test_bulk_apply_oversize_returns_400() {
    let (app, _state) = setup_test_app().await;
    let (session, csrf) = login_as(app.clone(), "curator", "Scholar2024!").await;

    let huge: Vec<String> = (0..1001).map(|i| format!("kp-{i}")).collect();
