            .bind(&order_id)
            .fetch_one(&self.db)
            .await?;
        Ok((order, result))
    }

    pub async fn list_orders(&self, user_id: Option<&str>, limit: i64) -> AppResult<Vec<Order>> {
        let rows = if let Some(u) = user_id {
