            if let Some(existing) = c.iter_mut().find(|i| i.product_id == p.id) {
                existing.quantity += 1;
            } else {
                c.push(CartItem {
                    product_id: p.id.clone(),
                    product_name: p.name.clone(),
                    quantity: 1,
                    unit_price: p.price,
                });
            }
        });
