1	//! ScholarVault backend entrypoint.
2	//!
3	//! Boots the SQLite pool (WAL mode), runs migrations, builds the Axum router and
4	//! listens on `HOST:PORT`. All real wiring lives in the `backend` library crate so
5	//! integration tests can construct the same router without spawning a process.
6	
7	use std::net::SocketAddr;
8	use std::sync::Arc;
9	
10	use backend::middleware::rate_limit::RateLimitState;
11	use backend::{db, derive_key, router::build_router, AppError, AppResult, AppState};
12	use tracing_subscriber::EnvFilter;
13	
14	#[tokio::main]
15	async fn main() -> AppResult<()> {
16	    tracing_subscriber::fmt()
17	        .with_env_filter(EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info")))
18	        .with_target(false)
19	        .compact()
20	        .init();
21	
22	    let database_url = std::env::var("DATABASE_URL")
23	        .unwrap_or_else(|_| "sqlite:///app/data/scholarvault.db".to_string());
24	    let encryption_key_material = std::env::var("ENCRYPTION_KEY")
25	        .unwrap_or_else(|_| "scholarvault-aes256-key-32bytes!!".to_string());
26	    let signing_key = std::env::var("SIGNING_KEY")
27	        .unwrap_or_else(|_| "scholarvault-jwt-signing-key-secret!".to_string());
28	    let host = std::env::var("HOST").unwrap_or_else(|_| "0.0.0.0".to_string());
29	    let port: u16 = std::env::var("PORT")
30	        .unwrap_or_else(|_| "3000".to_string())
31	        .parse()
32	        .map_err(|e| AppError::Internal(format!("invalid PORT: {e}")))?;
33	    let migrations_dir = std::env::var("MIGRATIONS_DIR")
34	        .unwrap_or_else(|_| "/app/migrations".to_string());
35	
36	    ensure_data_dir(&database_url)?;
37	
38	    tracing::info!(%database_url, "opening sqlite pool");
39	    let pool = db::init_pool(&database_url).await?;
40	
41	    db::run_migrations(&pool, &migrations_dir).await?;
42	
43	    let evidence_dir = std::path::PathBuf::from(
44	        std::env::var("EVIDENCE_DIR").unwrap_or_else(|_| "/app/evidence".to_string()),
45	    );
46	    let backup_dir = std::path::PathBuf::from(
47	        std::env::var("BACKUP_DIR").unwrap_or_else(|_| "/app/backups".to_string()),
48	    );
49	    let reports_dir = std::path::PathBuf::from(
50	        std::env::var("REPORTS_DIR").unwrap_or_else(|_| "/app/reports".to_string()),
51	    );
52	    let _ = std::fs::create_dir_all(&evidence_dir);
53	    let _ = std::fs::create_dir_all(&backup_dir);
54	    let _ = std::fs::create_dir_all(&reports_dir);
55	
56	    let state = AppState {
57	        db: pool,
58	        encryption_key: Arc::new(derive_key(&encryption_key_material)),
59	        signing_key: Arc::new(signing_key),
60	        rate_limit: RateLimitState::new(60),
61	        evidence_dir: Arc::new(evidence_dir),
62	        backup_dir: Arc::new(backup_dir),
63	        reports_dir: Arc::new(reports_dir),
64	    };
65	
66	    let app = build_router(state);
67	
68	    let addr: SocketAddr = format!("{host}:{port}")
69	        .parse()
70	        .map_err(|e| AppError::Internal(format!("bad bind address: {e}")))?;
71	    tracing::info!(%addr, "ScholarVault listening");
72	
73	    let listener = tokio::net::TcpListener::bind(addr)
74	        .await
75	        .map_err(|e| AppError::Internal(format!("bind failed: {e}")))?;
76	    axum::serve(
77	        listener,
78	        app.into_make_service_with_connect_info::<SocketAddr>(),
79	    )
80	    .await
81	    .map_err(|e| AppError::Internal(format!("serve failed: {e}")))?;
82	
83	    Ok(())
84	}
85	
86	/// Ensure the parent directory of a `sqlite://...` URL exists so SQLite can
87	/// create the database file at startup.
88	fn ensure_data_dir(database_url: &str) -> AppResult<()> {
89	    if let Some(rest) = database_url.strip_prefix("sqlite://") {
90	        let path = std::path::Path::new(rest);
91	        if let Some(parent) = path.parent() {
92	            if !parent.as_os_str().is_empty() {
93	                std::fs::create_dir_all(parent)
94	                    .map_err(|e| AppError::Internal(format!("create data dir: {e}")))?;
95	            }
96	        }
97	    }
98	    Ok(())
99	}
100

