                                                        on:click=move |_| validate(id_for_validate.clone())>"Validate"</button>
                                                    <button class="sv-btn-ghost" style="font-size:11px;padding:4px 8px;"
                                                        on:click=move |_| activate(id_for_activate.clone())>"Activate"</button>
