  border-radius: var(--radius-sm);
}
@keyframes sv-shimmer {
  0%   { background-position: -2000px 0; }
  100% { background-position:  2000px 0; }
}

.sv-empty {
  text-align: center;
  padding: 48px 24px;
  color: var(--text-muted);
}
.sv-empty-icon {
  width: 64px;
  height: 64px;
  border-radius: 50%;
  margin: 0 auto 14px;
  background: rgba(245,197,24,0.06);
  border: 1px solid var(--border-default);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 26px;
  color: var(--gold-400);
}
.sv-empty-title {
  font-size: 14px;
  color: var(--text-primary);
  font-weight: 600;
  margin-bottom: 4px;
}
.sv-empty-body { font-size: 12px; max-width: 320px; margin: 0 auto 16px; }

/* --------------------------------------------------------------------
   Modal
   -------------------------------------------------------------------- */

.sv-modal-overlay {
  position: fixed;
  inset: 0;
  background: rgba(4,4,8,0.80);
  backdrop-filter: blur(4px);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
  animation: sv-fade-in 0.2s ease;
}

.sv-modal {
  background: linear-gradient(180deg, var(--bg-card) 0%, var(--bg-secondary) 100%);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-lg);
  padding: 28px;
  min-width: 480px;
  max-width: 90vw;
  max-height: 90vh;
  overflow-y: auto;
  box-shadow: var(--shadow-gold-strong);
}

/* --------------------------------------------------------------------
   Tabs
   -------------------------------------------------------------------- */

.sv-tabs {
  display: flex;
  gap: 4px;
  padding: 4px;
  background: rgba(14,14,22,0.7);
  border: 1px solid var(--border-neutral);
  border-radius: var(--radius-md);
  margin-bottom: 24px;
  width: fit-content;
}
.sv-tab {
  padding: 10px 18px;
  font-size: 12px;
  font-weight: 600;
  color: var(--text-secondary);
  background: transparent;
  border: none;
  border-radius: var(--radius-sm);
  cursor: pointer;
  transition: all 0.18s cubic-bezier(0.2,0.8,0.2,1);
  letter-spacing: 0.02em;
}
.sv-tab:hover { color: var(--text-primary); background: rgba(255,255,255,0.03); }
.sv-tab.active {
  background: linear-gradient(180deg, rgba(245,197,24,0.14) 0%, rgba(245,197,24,0.06) 100%);
  color: var(--gold-400);
  box-shadow: inset 0 0 0 1px rgba(245,197,24,0.35);
}

/* --------------------------------------------------------------------
   Page header
   -------------------------------------------------------------------- */

.sv-page-header {
  margin-bottom: 26px;
}
.sv-page-title {
  font-size: 28px;
  font-weight: 800;
  letter-spacing: -0.025em;
  background: var(--gradient-gold);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  margin: 0;
}
.sv-page-subtitle {
  color: var(--text-secondary);
  font-size: 13px;
  margin-top: 6px;
  font-weight: 400;
}

/* --------------------------------------------------------------------
   Utility classes
   -------------------------------------------------------------------- */

.sv-text-gradient {
  background: var(--gradient-gold);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}

.sv-text-muted { color: var(--text-muted); }
.sv-text-sec   { color: var(--text-secondary); }
.sv-text-gold  { color: var(--gold-400); }

.sv-hash {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-muted);
  background: rgba(255,255,255,0.03);
  padding: 2px 6px;
  border-radius: 4px;
}

.sv-divider {
  height: 1px;
  background: linear-gradient(90deg, transparent 0%, var(--border-default) 50%, transparent 100%);
  margin: 16px 0;
}

.sv-grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
.sv-grid-3 { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
.sv-grid-4 { display: grid; grid-template-columns: repeat(4, 1fr); gap: 16px; }

/* --------------------------------------------------------------------
   Login page specific
   -------------------------------------------------------------------- */

.sv-login-bg {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 20px;
  background:
    radial-gradient(ellipse at 20% 20%, rgba(245,197,24,0.10) 0%, transparent 45%),
    radial-gradient(ellipse at 80% 80%, rgba(232,169,0,0.08) 0%, transparent 45%),
    linear-gradient(180deg, #07070B 0%, #0A0A10 100%);
  position: relative;
}
.sv-login-bg::before {
  content: '';
  position: absolute;
  inset: 0;
  background-image:
    linear-gradient(rgba(245,197,24,0.02) 1px, transparent 1px),
    linear-gradient(90deg, rgba(245,197,24,0.02) 1px, transparent 1px);
  background-size: 40px 40px;
  pointer-events: none;
  mask-image: radial-gradient(ellipse at center, black 30%, transparent 70%);
  -webkit-mask-image: radial-gradient(ellipse at center, black 30%, transparent 70%);
}

.sv-login-card {
  width: 100%;
  max-width: 440px;
  background: linear-gradient(180deg, rgba(20,20,30,0.92) 0%, rgba(14,14,22,0.92) 100%);
  backdrop-filter: blur(24px);
  -webkit-backdrop-filter: blur(24px);
  border: 1px solid var(--border-default);
  border-radius: var(--radius-xl);
  padding: 44px 40px 36px;
  box-shadow:
    0 0 0 1px rgba(245,197,24,0.08),
    0 24px 80px rgba(0,0,0,0.6),
    0 0 100px rgba(245,197,24,0.10);
  position: relative;
  z-index: 1;
  animation: sv-fade-in 0.5s cubic-bezier(0.2,0.8,0.2,1);
}
.sv-login-logo {
  text-align: center;
  margin-bottom: 32px;
}
.sv-login-mark {
  font-size: 40px;
  font-weight: 900;
  letter-spacing: -0.04em;
  background: var(--gradient-gold);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
  text-shadow: 0 0 40px rgba(245,197,24,0.3);
}
.sv-login-tag {
  font-size: 11px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.20em;
  margin-top: 8px;
  font-weight: 600;
}

/* --------------------------------------------------------------------
   Dashboard-specific helpers
   -------------------------------------------------------------------- */

.sv-chart-wrap {
  background: var(--bg-card);
  border: 1px solid var(--border-neutral);
  border-left: 3px solid var(--gold-500);
  border-radius: var(--radius-md);
  padding: 20px;
  transition: box-shadow 0.25s;
}
.sv-chart-wrap:hover { box-shadow: var(--shadow-gold-soft); }

/* Step indicator */
.sv-step {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: var(--radius-sm);
  font-size: 12px;
  color: var(--text-muted);
  font-weight: 500;
  border-left: 3px solid transparent;
}
.sv-step.active {
  background: rgba(245,197,24,0.08);
  color: var(--gold-400);
  border-left-color: var(--gold-400);
  font-weight: 700;
}
.sv-step-num {
  width: 22px;
  height: 22px;
  border-radius: 50%;
  background: rgba(245,197,24,0.10);
  border: 1px solid var(--border-default);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 11px;
  font-weight: 700;
  color: var(--gold-400);
}
.sv-step.active .sv-step-num { background: var(--gradient-gold); color: #0A0A0F; border-color: transparent; }
"}

