{"file_path": "/home/abdelah/Documents/eaglepoint/TASK-32-W2/repo/frontend/src/components/layout/mod.rs", "content": "//! Layout chrome — sidebar + topbar + `PageShell` used by every authenticated
//! page. Pure presentation; no backend or business logic touched.

use leptos::*;
use wasm_bindgen_futures::spawn_local;

use crate::api::auth as auth_api;
use crate::api::client::post_json;

/// Navigation entries that can be rendered in the sidebar. `NavTarget` is a
/// lightweight tag used by every page to mark which item is currently active.
#[derive(Clone, Copy, PartialEq, Eq)]
pub enum NavTarget {
    Knowledge,
    Outcomes,
    Store,
    Analytics,
    Admin,
}

impl NavTarget {
    fn from_role(role: &str) -> Self {
        match role {
            "administrator" => Self::Admin,
            "content_curator" => Self::Knowledge,
            "reviewer" => Self::Outcomes,
            "finance_manager" => Self::Analytics,
            "store_manager" => Self::Store,
            _ => Self::Knowledge,
        }
    }
}

#[derive(Clone)]
struct NavEntry {
    label: &'static str,
    icon: &'static str,
    href: &'static str,
    target: NavTarget,
}

const NAV: &[NavEntry] = &[
    NavEntry { label: "Knowledge",  icon: "◆", href: "/knowledge", target: NavTarget::Knowledge },
    NavEntry { label: "Outcomes",   icon: "◈", href: "/outcomes",  target: NavTarget::Outcomes },
    NavEntry { label: "Store",      icon: "◉", href: "/store",     target: NavTarget::Store },
    NavEntry { label: "Analytics",  icon: "◎", href: "/analytics", target: NavTarget::Analytics },
    NavEntry { label: "Administrator", icon: "◇", href: "/admin",  target: NavTarget::Admin },
];

fn role_display_name(role: &str) -> &'static str {
    match role {
        "administrator" => "Administrator",
        "content_curator" => "Content Curator",
        "reviewer" => "Reviewer",
        "finance_manager" => "Finance Manager",
        "store_manager" => "Store Manager",
        _ => "User",
    }
}

/// Full-page shell: golden-gradient sidebar on the left, sticky topbar with
/// the page title + breadcrumbs on top, and the caller's children rendered
/// inside the `.sv-content` area.
#[component]
pub fn PageShell(
    active: NavTarget,
    #[prop(into)] title: String,
    #[prop(into)] subtitle: String,
    children: Children,
) -> impl IntoView {
    let me = create_resource(|| (), |_| async move { auth_api::me().await });

    let do_logout = move |_| {
        spawn_local(async move {
