pub enum NavTarget {
    Knowledge,
    Outcomes,
    Store,
    Analytics,
    Admin,
}

impl NavTarget {
    fn from_role(role: &str) -> Self {
        match role {
            "administrator" => Self::Admin,
            "content_curator" => Self::Knowledge,
            "reviewer" => Self::Outcomes,
            "finance_manager" => Self::Analytics,
            "store_manager" => Self::Store,
            _ => Self::Knowledge,
        }
    }
}

#[derive(Clone)]
struct NavEntry {
    label: &'static str,
    icon: &'static str,
    href: &'static str,
    target: NavTarget,
}

const NAV: &[NavEntry] = &[
    NavEntry { label: "Knowledge",  icon: "◆", href: "/knowledge", target: NavTarget::Knowledge },
    NavEntry { label: "Outcomes",   icon: "◈", href: "/outcomes",  target: NavTarget::Outcomes },
    NavEntry { label: "Store",      icon: "◉", href: "/store",     target: NavTarget::Store },
    NavEntry { label: "Analytics",  icon: "◎", href: "/analytics", target: NavTarget::Analytics },
    NavEntry { label: "Administrator", icon: "◇", href: "/admin",  target: NavTarget::Admin },
];

fn role_display_name(role: &str) -> &'static str {
    match role {
        "administrator" => "Administrator",
        "content_curator" => "Content Curator",
        "reviewer" => "Reviewer",
        "finance_manager" => "Finance Manager",
        "store_manager" => "Store Manager",
        _ => "User",
    }
}

