                            let label = role_display_name(&m.role).to_string();
                            view! {
                                <span class=role_class>{label}</span>
                            }
                        })}
                    </div>
                </header>
                <div class="sv-content">
                    {children()}
                </div>
            </main>
        </div>
    }
}
