1	//! Layout chrome — sidebar + topbar + `PageShell` used by every authenticated
2	//! page. Pure presentation; no backend or business logic touched.
3	
4	use leptos::*;
5	use wasm_bindgen_futures::spawn_local;
6	
7	use crate::api::auth as auth_api;
8	use crate::api::client::post_json;
9	
10	/// Navigation entries that can be rendered in the sidebar. `NavTarget` is a
11	/// lightweight tag used by every page to mark which item is currently active.
12	#[derive(Clone, Copy, PartialEq, Eq)]
13	pub enum NavTarget {
14	    Knowledge,
15	    Outcomes,
16	    Store,
17	    Analytics,
18	    Admin,
19	}
20	
21	impl NavTarget {
22	    fn from_role(role: &str) -> Self {
23	        match role {
24	            "administrator" => Self::Admin,
25	            "content_curator" => Self::Knowledge,
26	            "reviewer" => Self::Outcomes,
27	            "finance_manager" => Self::Analytics,
28	            "store_manager" => Self::Store,
29	            _ => Self::Knowledge,
30	        }
31	    }
32	}
33	
34	#[derive(Clone)]
35	struct NavEntry {
36	    label: &'static str,
37	    icon: &'static str,
38	    href: &'static str,
39	    target: NavTarget,
40	}
41	
42	const NAV: &[NavEntry] = &[
43	    NavEntry { label: "Knowledge",  icon: "◆", href: "/knowledge", target: NavTarget::Knowledge },
44	    NavEntry { label: "Outcomes",   icon: "◈", href: "/outcomes",  target: NavTarget::Outcomes },
45	    NavEntry { label: "Store",      icon: "◉", href: "/store",     target: NavTarget::Store },
46	    NavEntry { label: "Analytics",  icon: "◎", href: "/analytics", target: NavTarget::Analytics },
47	    NavEntry { label: "Administrator", icon: "◇", href: "/admin",  target: NavTarget::Admin },
48	];
49	
50	fn role_display_name(role: &str) -> &'static str {
51	    match role {
52	        "administrator" => "Administrator",
53	        "content_curator" => "Content Curator",
54	        "reviewer" => "Reviewer",
55	        "finance_manager" => "Finance Manager",
56	        "store_manager" => "Store Manager",
57	        _ => "User",
58	    }
59	}
60	
61	/// Full-page shell: golden-gradient sidebar on the left, sticky topbar with
62	/// the page title + breadcrumbs on top, and the caller's children rendered
63	/// inside the `.sv-content` area.
64	#[component]
65	pub fn PageShell(
66	    active: NavTarget,
67	    #[prop(into)] title: String,
68	    #[prop(into)] subtitle: String,
69	    children: Children,
70	) -> impl IntoView {
71	    let me = create_resource(|| (), |_| async move { auth_api::me().await });
72	
73	    let do_logout = move |_| {
74	        spawn_local(async move {
75	            let _: Result<serde_json::Value, _> =
76	                post_json("/api/auth/logout", &serde_json::json!({})).await;
77	            #[cfg(target_arch = "wasm32")]
78	            {
79	                if let Some(window) = web_sys::window() {
80	                    let _ = window.location().set_href("/login");
81	                }
82	            }
83	        });
84	    };
85	
86	    view! {
87	        <div class="sv-app">
88	            <aside class="sv-sidebar">
89	                <div class="sv-sidebar-logo">
90	                    <span class="sv-sidebar-logo-text">"ScholarVault"</span>
91	                    <div class="sv-sidebar-logo-sub">"Research · Commerce · IP"</div>
92	                </div>
93	
94	                <div class="sv-sidebar-section">"Workspace"</div>
95	                {NAV.iter().map(|n| {
96	                    let is_active = n.target == active;
97	                    let class = if is_active { "sv-sidebar-item active" } else { "sv-sidebar-item" };
98	                    view! {
99	                        <a class=class href=n.href>
100	                            <span class="sv-sidebar-icon">{n.icon}</span>
101	                            <span>{n.label}</span>
102	                        </a>
103	                    }
104	                }).collect_view()}
105	
106	                <div class="sv-sidebar-footer">
107	                    {move || {
108	                        let user = me.get();
109	                        let (username, role, initial) = match user {
110	                            Some(Ok(ref m)) => (
111	                                m.username.clone(),
112	                                m.role.clone(),
113	                                m.username.chars().next().map(|c| c.to_ascii_uppercase().to_string()).unwrap_or_else(|| "?".into()),
114	                            ),
115	                            _ => ("loading".into(), "".into(), "·".into()),
116	                        };
117	                        let role_class = format!("sv-badge sv-role-{}", role);
118	                        view! {
119	                            <div class="sv-role-pill">
120	                                <div class="sv-role-avatar">{initial}</div>
121	                                <div class="sv-role-meta">
122	                                    <div class="sv-role-username">{username}</div>
123	                                    <div class="sv-role-label">
124	                                        {if role.is_empty() {
125	                                            "—".to_string()
126	                                        } else {
127	                                            role_display_name(&role).to_string()
128	                                        }}
129	                                    </div>
130	                                </div>
131	                            </div>
132	                            <span class=role_class style="display:none;"></span>
133	                        }
134	                    }}
135	                    <button class="sv-sidebar-logout" on:click=do_logout>"Sign out"</button>
136	                </div>
137	            </aside>
138	
139	            <main class="sv-main">
140	                <header class="sv-topbar">
141	                    <div>
142	                        <div class="sv-topbar-title">{title.clone()}</div>
143	                        <div class="sv-topbar-crumbs">{subtitle.clone()}</div>
144	                    </div>
145	                    <div class="sv-topbar-right">
146	                        {move || me.get().and_then(|r| r.ok()).map(|m| {
147	                            let role_class = format!("sv-badge sv-role-{}", m.role);
148	                            let label = role_display_name(&m.role).to_string();
149	                            view! {
150	                                <span class=role_class>{label}</span>
151	                            }
152	                        })}
153	                    </div>
154	                </header>
155	                <div class="sv-content">
156	                    {children()}
157	                </div>
158	            </main>
159	        </div>
160	    }
161	}
162

